import { describe, expect, it } from "vitest";
import { parseQuery } from "../src/parseQuery.js";

describe("parseQuery", () => {
  describe("empty and trivial inputs", () => {
    it("returns an empty object for an empty string", () => {
      expect(parseQuery("")).toEqual({});
    });

    it("returns an empty object for a lone '?'", () => {
      expect(parseQuery("?")).toEqual({});
    });

    it("returns an empty object for only separators", () => {
      expect(parseQuery("&")).toEqual({});
      expect(parseQuery("&&&")).toEqual({});
      expect(parseQuery("?&&")).toEqual({});
    });

    it("returns a plain object with no inherited enumerable keys", () => {
      const result = parseQuery("a=1");
      expect(Object.keys(result)).toEqual(["a"]);
    });
  });

  describe("leading '?' handling", () => {
    it("strips a single leading '?'", () => {
      expect(parseQuery("?a=1")).toEqual({ a: "1" });
    });

    it("parses fine without a leading '?'", () => {
      expect(parseQuery("a=1")).toEqual({ a: "1" });
    });

    it("strips only the first '?', keeping the rest as part of the key", () => {
      expect(parseQuery("??a=1")).toEqual({ "?a": "1" });
    });

    it("treats a '?' that is not leading as a literal character", () => {
      expect(parseQuery("a=?")).toEqual({ a: "?" });
      expect(parseQuery("a?b=1")).toEqual({ "a?b": "1" });
    });
  });

  describe("single key/value pairs", () => {
    it("maps a key to its string value", () => {
      expect(parseQuery("a=1")).toEqual({ a: "1" });
    });

    it("keeps values as strings, never coercing to numbers or booleans", () => {
      const result = parseQuery("n=42&b=true");
      expect(result).toEqual({ n: "42", b: "true" });
      expect(typeof result.n).toBe("string");
      expect(typeof result.b).toBe("string");
    });

    it("maps a key with an empty value to an empty string", () => {
      expect(parseQuery("a=")).toEqual({ a: "" });
    });

    it("allows an empty key from a leading '='", () => {
      expect(parseQuery("=v")).toEqual({ "": "v" });
    });

    it("maps an empty key with an empty value", () => {
      expect(parseQuery("=")).toEqual({ "": "" });
    });
  });

  describe("multiple pairs", () => {
    it("parses several distinct keys", () => {
      expect(parseQuery("a=1&b=2&c=3")).toEqual({ a: "1", b: "2", c: "3" });
    });

    it("skips empty segments between pairs", () => {
      expect(parseQuery("a=1&&b=2")).toEqual({ a: "1", b: "2" });
    });

    it("skips leading and trailing separators", () => {
      expect(parseQuery("&a=1&b=2&")).toEqual({ a: "1", b: "2" });
    });

    it("skips runs of consecutive separators", () => {
      expect(parseQuery("a=1&&&&b=2")).toEqual({ a: "1", b: "2" });
    });
  });

  describe("bare keys (no '=')", () => {
    it("maps a bare key to an empty string", () => {
      expect(parseQuery("flag")).toEqual({ flag: "" });
    });

    it("mixes bare keys with valued keys", () => {
      expect(parseQuery("flag&a=1")).toEqual({ flag: "", a: "1" });
    });

    it("distinguishes a bare key from an empty-valued key (both empty string)", () => {
      expect(parseQuery("flag")).toEqual(parseQuery("flag="));
    });
  });

  describe("the '=' separator", () => {
    it("splits on the first '=' only, keeping later '=' in the value", () => {
      expect(parseQuery("a=b=c")).toEqual({ a: "b=c" });
    });

    it("preserves an '=' immediately after the split as part of the value", () => {
      expect(parseQuery("a==")).toEqual({ a: "=" });
    });

    it("keeps a value that is entirely '=' characters", () => {
      expect(parseQuery("a=====")).toEqual({ a: "====" });
    });
  });

  describe("repeated keys", () => {
    it("collects two occurrences into an array in order", () => {
      expect(parseQuery("a=1&a=2")).toEqual({ a: ["1", "2"] });
    });

    it("collects three or more occurrences into a single array in order", () => {
      expect(parseQuery("a=1&a=2&a=3&a=4")).toEqual({ a: ["1", "2", "3", "4"] });
    });

    it("preserves order even when other keys are interleaved", () => {
      expect(parseQuery("a=1&b=x&a=2&b=y&a=3")).toEqual({
        a: ["1", "2", "3"],
        b: ["x", "y"],
      });
    });

    it("returns a string (not an array) for a key seen exactly once", () => {
      const result = parseQuery("a=1");
      expect(Array.isArray(result.a)).toBe(false);
      expect(result.a).toBe("1");
    });

    it("returns an actual array for a repeated key", () => {
      const result = parseQuery("a=1&a=2");
      expect(Array.isArray(result.a)).toBe(true);
    });

    it("collects repeated bare keys into an array of empty strings", () => {
      expect(parseQuery("flag&flag")).toEqual({ flag: ["", ""] });
    });

    it("collects repeated empty-valued keys into an array", () => {
      expect(parseQuery("a=&a=")).toEqual({ a: ["", ""] });
    });

    it("preserves empty-string values within a repeated-key array", () => {
      expect(parseQuery("a=1&a=&a=3")).toEqual({ a: ["1", "", "3"] });
    });

    it("groups keys that are only equal after decoding", () => {
      // "a%62" and "ab" both decode to "ab".
      expect(parseQuery("a%62=1&ab=2")).toEqual({ ab: ["1", "2"] });
    });
  });

  describe("'+' decoding", () => {
    it("decodes '+' to a space in values", () => {
      expect(parseQuery("a=hello+world")).toEqual({ a: "hello world" });
    });

    it("decodes '+' to a space in keys", () => {
      expect(parseQuery("first+name=jane")).toEqual({ "first name": "jane" });
    });

    it("decodes multiple '+' characters to multiple spaces", () => {
      expect(parseQuery("a=x+++y")).toEqual({ a: "x   y" });
    });

    it("decodes a '+' in both key and value of the same pair", () => {
      expect(parseQuery("a+b=c+d")).toEqual({ "a b": "c d" });
    });
  });

  describe("percent decoding", () => {
    it("percent-decodes a space in a value", () => {
      expect(parseQuery("a=%20")).toEqual({ a: " " });
    });

    it("percent-decodes a value with reserved characters", () => {
      expect(parseQuery("a=%26%3D%3F")).toEqual({ a: "&=?" });
    });

    it("percent-decodes keys", () => {
      expect(parseQuery("a%20b=1")).toEqual({ "a b": "1" });
    });

    it("percent-decodes multi-byte UTF-8 sequences", () => {
      expect(parseQuery("check=%E2%9C%93")).toEqual({ check: "✓" });
      expect(parseQuery("name=%C3%A9")).toEqual({ name: "é" });
    });

    it("decodes '%2B' to a literal '+' because '+' replacement runs first", () => {
      // There is no literal '+' in "%2B", so the space-substitution is a no-op
      // and decodeURIComponent turns "%2B" into "+".
      expect(parseQuery("a=%2B")).toEqual({ a: "+" });
      expect(parseQuery("%2B=%2B")).toEqual({ "+": "+" });
    });

    it("applies '+' replacement before percent-decoding", () => {
      // "+" -> space, then "%20" -> space, yielding two spaces.
      expect(parseQuery("a=x+%20y")).toEqual({ a: "x  y" });
    });
  });

  describe("malformed percent sequences never throw", () => {
    it("returns the raw value when percent-decoding fails", () => {
      expect(parseQuery("a=%")).toEqual({ a: "%" });
      expect(parseQuery("a=%zz")).toEqual({ a: "%zz" });
      expect(parseQuery("a=100%")).toEqual({ a: "100%" });
    });

    it("returns the raw key when key decoding fails", () => {
      expect(parseQuery("%=v")).toEqual({ "%": "v" });
      expect(parseQuery("bad%key=v")).toEqual({ "bad%key": "v" });
    });

    it("still applies '+' replacement on the decode-failure fallback path", () => {
      // "a+%" -> "a %" (plus replaced), decode fails, raw "a %" is used.
      expect(parseQuery("a+%=x")).toEqual({ "a %": "x" });
    });

    it("handles a lone incomplete escape at the end of a token", () => {
      expect(parseQuery("a=hi%2")).toEqual({ a: "hi%2" });
    });

    it("does not throw on any malformed input", () => {
      expect(() => parseQuery("%&%=%&a=%zz&%")).not.toThrow();
    });
  });

  describe("combined and realistic inputs", () => {
    it("parses a mixed query with '?', repeats, bare keys, and encoding", () => {
      expect(parseQuery("?q=hello+world&tag=a&tag=b&debug&limit=10")).toEqual({
        q: "hello world",
        tag: ["a", "b"],
        debug: "",
        limit: "10",
      });
    });

    it("round-trips values encoded with encodeURIComponent", () => {
      const value = "a b&c=d/e?f#g";
      const encoded = encodeURIComponent(value);
      expect(parseQuery(`k=${encoded}`)).toEqual({ k: value });
    });

    it("preserves a value containing an encoded newline and tab", () => {
      expect(parseQuery("a=%0A%09")).toEqual({ a: "\n\t" });
    });
  });

  describe("purity and independence", () => {
    it("returns independent objects across calls", () => {
      const a = parseQuery("x=1");
      const b = parseQuery("x=1");
      expect(a).not.toBe(b);
      a.x = "mutated";
      expect(b.x).toBe("1");
    });

    it("returns a fresh array per call for repeated keys", () => {
      const a = parseQuery("x=1&x=2");
      const b = parseQuery("x=1&x=2");
      expect(a.x).not.toBe(b.x);
    });
  });
});

